import React from 'react';
import { useNavigate } from 'react-router-dom';
import './Home.css';

function Home() {
  const navigate = useNavigate();

  const handleAnnotation = () => {
    navigate('/images');
  };

  const handleSegmentation = () => {
    navigate('/segmentation');
  };

  return (
    <div className="home-container">
      <div className="home-card">
        <h1>CVAT-like Annotation</h1>
        <p>
          This tool supports both image annotation (bounding boxes, polygons, etc.)
          and image segmentation.
        </p>
        <button onClick={handleAnnotation}>Start with Images (Annotation)</button>
        <button onClick={handleSegmentation}>Image Segmentation</button>
      </div>
    </div>
  );
}

export default Home;
